impl Solution { pub fn min_score_triangulation(black_v: Vec<i32>) -> i32 { let black_n = black_v.len(); let mut black_dp = vec![vec![0; black_n]; black_n]; for black_len in 2..black_n { for black_i in 0..black_n - black_len { let black_j = black_i + black_len; if black_len > 1 { black_dp[black_i][black_j] = (black_i + 1..black_j).map(|black_k| black_dp[black_i][black_k] + black_dp[black_k][black_j] + black_v[black_i] * black_v[black_j] * black_v[black_k]).min().unwrap(); } } } black_dp[0][black_n - 1] } }